from dataclasses import dataclass
from typing import Tuple


@dataclass
class MOSFETParams:
    """MOSFET device parameters."""
    mu_cox: float      # mu_n * C_ox in uA/V^2
    w_over_l: float    # W/L ratio (dimensionless)
    v_th: float        # Threshold voltage in V
    lambda_: float     # Channel-length modulation in V^-1


def mosfet_current(
    params: MOSFETParams,
    v_gs: float,
    v_ds: float
) -> Tuple[str, float]:
    """Calculate MOSFET drain current."""
    v_ov = v_gs - params.v_th  # Overdrive voltage

    if v_ov <= 0:
        return ('cutoff', 0.0)

    clm = 1.0 + params.lambda_ * v_ds  # Channel-length modulation factor
    k = params.mu_cox * params.w_over_l  # Process parameter * sizing

    if v_ds >= v_ov:
        # Saturation region
        i_d = 0.5 * k * v_ov ** 2 * clm
        return ('saturation', i_d)
    else:
        # Linear (triode) region
        i_d = k * (v_ov * v_ds - 0.5 * v_ds ** 2) * clm
        return ('linear', i_d)


def cmos_dynamic_power(
    alpha: float,
    c_load_nf: float,
    v_dd: float,
    freq_ghz: float
) -> float:
    """Calculate CMOS dynamic power consumption."""
    c_load_f = c_load_nf * 1e-9      # Convert nF to F
    freq_hz = freq_ghz * 1e9          # Convert GHz to Hz
    power_w = alpha * c_load_f * v_dd ** 2 * freq_hz
    return power_w

from typing import List, Set, Tuple, Optional
from dataclasses import dataclass


@dataclass(frozen=True)
class Implicant:
    """Represents an implicant in K-map minimization."""
    minterms: frozenset
    mask: int
    value: int


def can_combine(imp1: Implicant, imp2: Implicant) -> Optional[Implicant]:
    """Try to combine two implicants that differ in exactly one variable."""
    if imp1.mask != imp2.mask:
        return None
    diff = imp1.value ^ imp2.value
    # Check that the difference is only in bits that are still present
    diff = diff & imp1.mask
    # Must differ in exactly one bit
    if diff == 0 or (diff & (diff - 1)) != 0:
        return None
    new_mask = imp1.mask & ~diff
    new_value = imp1.value & new_mask
    new_minterms = imp1.minterms | imp2.minterms
    return Implicant(minterms=new_minterms, mask=new_mask, value=new_value)


def find_prime_implicants(
    n_vars: int,
    minterms: List[int],
    dont_cares: List[int] = None
) -> List[Implicant]:
    """Find all prime implicants using iterative combining."""
    if dont_cares is None:
        dont_cares = []

    all_terms = set(minterms) | set(dont_cares)
    full_mask = (1 << n_vars) - 1

    current = set()
    for m in all_terms:
        current.add(Implicant(
            minterms=frozenset([m]),
            mask=full_mask,
            value=m
        ))

    prime_implicants = set()

    while current:
        combined = set()
        used = set()
        implicant_list = list(current)

        for i in range(len(implicant_list)):
            for j in range(i + 1, len(implicant_list)):
                result = can_combine(implicant_list[i], implicant_list[j])
                if result is not None:
                    combined.add(result)
                    used.add(implicant_list[i])
                    used.add(implicant_list[j])

        for imp in current:
            if imp not in used:
                prime_implicants.add(imp)

        current = combined

    return list(prime_implicants)


def implicant_to_string(imp: Implicant, n_vars: int) -> str:
    """Convert an implicant to a human-readable product term."""
    var_names = ['A', 'B', 'C', 'D'][:n_vars]
    result = []
    for i in range(n_vars):
        bit_pos = n_vars - 1 - i
        if imp.mask & (1 << bit_pos):
            if imp.value & (1 << bit_pos):
                result.append(var_names[i])
            else:
                result.append(var_names[i] + "'")
    if not result:
        return '1'  # Tautology
    return ''.join(result)


def minimize_sop(
    n_vars: int,
    minterms: List[int],
    dont_cares: List[int] = None
) -> List[str]:
    """Find minimal sum-of-products expression using greedy cover."""
    if dont_cares is None:
        dont_cares = []
    if not minterms:
        return ['0']

    primes = find_prime_implicants(n_vars, minterms, dont_cares)
    minterm_set = set(minterms)

    # Find essential prime implicants
    essential = []
    covered = set()

    for m in minterms:
        covering_primes = [p for p in primes if m in p.minterms]
        if len(covering_primes) == 1:
            if covering_primes[0] not in essential:
                essential.append(covering_primes[0])
                covered |= (covering_primes[0].minterms & minterm_set)

    # Greedy cover remaining minterms
    remaining = minterm_set - covered
    selected = list(essential)

    while remaining:
        best = None
        best_count = -1
        for p in primes:
            if p in selected:
                continue
            count = len(p.minterms & remaining)
            if count > best_count:
                best_count = count
                best = p
        if best is None:
            break
        selected.append(best)
        covered |= (best.minterms & minterm_set)
        remaining = minterm_set - covered

    return [implicant_to_string(s, n_vars) for s in selected]

from typing import List


class BitSet:
    """A set of integers [0, max_element) represented as a bitmask."""

    def __init__(self, max_element: int = 32):
        self.max_element = max_element
        self.bits = 0

    @classmethod
    def from_list(cls, elements: List[int], max_element: int = 32) -> 'BitSet':
        """Create a BitSet from a list of elements."""
        bs = cls(max_element)
        for e in elements:
            bs.add(e)
        return bs

    def _make_result(self, bits: int) -> 'BitSet':
        """Helper to create a new BitSet with given bits."""
        result = BitSet(self.max_element)
        result.bits = bits
        return result

    def add(self, k: int) -> None:
        """Add element k to the set."""
        self.bits = self.bits | (1 << k)

    def remove(self, k: int) -> None:
        """Remove element k from the set."""
        self.bits = self.bits & ~(1 << k)

    def contains(self, k: int) -> bool:
        """Check if element k is in the set."""
        return bool(self.bits & (1 << k))

    def union(self, other: 'BitSet') -> 'BitSet':
        """Return new BitSet = self | other."""
        return self._make_result(self.bits | other.bits)

    def intersection(self, other: 'BitSet') -> 'BitSet':
        """Return new BitSet = self & other."""
        return self._make_result(self.bits & other.bits)

    def difference(self, other: 'BitSet') -> 'BitSet':
        """Return new BitSet = self - other."""
        return self._make_result(self.bits & ~other.bits)

    def symmetric_difference(self, other: 'BitSet') -> 'BitSet':
        """Return new BitSet = self ^ other."""
        return self._make_result(self.bits ^ other.bits)

    def complement(self) -> 'BitSet':
        """Return new BitSet with all elements NOT in self."""
        universe = (1 << self.max_element) - 1
        return self._make_result(~self.bits & universe)

    def popcount(self) -> int:
        """Count number of elements (set bits)."""
        count = 0
        n = self.bits
        while n:
            count += n & 1
            n >>= 1
        return count

    def is_subset(self, other: 'BitSet') -> bool:
        """Check if self is a subset of other."""
        return (self.bits & other.bits) == self.bits

    def to_list(self) -> List[int]:
        """Return sorted list of elements."""
        result = []
        for i in range(self.max_element):
            if self.bits & (1 << i):
                result.append(i)
        return result
